class Solution:
    def binaryGap(self, n: int) -> int:
        binary_str = bin(n)[2:]
        prev = -1
        max_gap = 0
        for i in range(len(binary_str)):
            if binary_str[i] == '1':
                if prev != -1:
                    current_gap = i - prev
                    if current_gap > max_gap:
                        max_gap = current_gap
                prev = i
        return max_gap

